453 static void setDeducedOverflowingFlags(Value *V, Instruction::BinaryOps Opcode,
454                                        bool NewNSW, bool NewNUW) {
455   Statistic *OpcNW, *OpcNSW, *OpcNUW;
456   switch (Opcode) {
